+    #[test]
+    fn static_identity_provider_empty_returns_false() {
+        let provider = StaticIdentityProvider::default();
+        let identity = ProcessIdentity {
+            pid: ProcessId(1),
+            start_id: StartId("boot:1:1".to_string()),
