+        let plan = make_plan();
+        let dir = tempdir().unwrap();
+        let runner = NoopActionRunner;
+        let identity_provider = StaticIdentityProvider::default();
+        let executor = ActionExecutor::new(&runner, &identity_provider, dir.path().join("lock"));
